def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 8):
            weight = (8 - j) / 28
            partial_ratio = ratio ** j
            if j % 2 == 0:
                partial_ratio *= 1.1
            else:
                partial_ratio *= 0.9
            score += weight * partial_ratio
        if capacity < item * 1.2:
            score *= 1.3
            for k in range(3):
                score += 0.05 * (k + 1) * (item / (capacity + 1))
        elif capacity > item * 4:
            score *= 0.7
            for k in range(2, 5):
                score -= 0.03 * k * (capacity / (item + 1))
        else:
            for m in range(1, 4):
                if (capacity / item) > m:
                    score += 0.02 * m
                else:
                    score -= 0.01 * m
        if score < 0:
            score = 0
        priorities[i] = score
    return priorities
